  ('dietitian-moex-08358', 'dietitian', 'dietitian-moex-099-da9d23a3', 'sub-dietitian-06', NULL, 'single_choice', '含氰配糖體化合物會被植物本身所含之酵素分解，而產生氰酸，下列何種植物不含此化合物？', '["利馬豆", "花椰菜", "苦杏仁", "未成熟竹筍之尖端"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:49+00:00", "source_pdf_sha1": "a7ac7f8b80cf", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "099010", "c": "109", "s": "600", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "食品衛生與安全", "year": "099", "exam_name": "099年第一次醫事人員、中醫師、營養師、心理師、語言治療師、醫師分試、社會工作師", "original_question_number": 32, "answer_corrected": false, "flags": ["answer_missing"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
